   ============================================ */

@layer theme {
  :root {
    /* ----------------------------------------
       COLOR PALETTE — Warp Warm Dark
       Warm near-black canvas, cream parchment text
       Almost monochromatic warm grays
       ---------------------------------------- */

    /* Background — warm near-black, not cold */
    --bg: #0e0e0d;

    /* Surface — warm dark */
    --surface: #181816;
    --surface-elevated: #222220;

    /* Text hierarchy — warm, not pure white */
    --text: #faf9f6;
    --text-secondary: #afaeac;
    --text-muted: #868584;
    --text-faint: #666469;

    /* Borders — semi-transparent warm */
    --border: rgba(226, 226, 226, 0.18);
    --border-strong: rgba(226, 226, 226, 0.35);

    /* Buttons — earthy dark, muted text */
    --btn-bg: #353534;
    --btn-text: #afaeac;
    --btn-border: rgba(255, 255, 255, 0.08);
    --btn-hover-bg: #404040;
    --btn-hover-text: #faf9f6;

    /* CTAs — restrained, no bright accents */
    --cta-bg: #faf9f6;
    --cta-text: #0e0e0d;
    --cta-hover-bg: #e8e7e4;

    /* Compat vars for hosted /webui-style docs pages */
    --accent: #d7b46a;
    --accent-soft: rgba(215, 180, 106, 0.12);
    --success: #7dbeb3;

    /* Surface overlays */
    --frosted: rgba(255, 255, 255, 0.04);
    --veil: rgba(255, 255, 255, 0.06);

    /* Grid — barely visible warm lines */
    --grid-color: rgba(255, 255, 255, 0.02);
    --grid-size: 64px;

    /* Font families — Matter-inspired DM Sans + Inter supplement */
    --font-matter: var(--font-dm-sans), -apple-system, BlinkMacSystemFont, sans-serif;
    --font-sans: var(--font-inter), -apple-system, BlinkMacSystemFont, sans-serif;
    --font-mono: var(--font-jetbrains), ui-monospace, monospace;

    /* Border radius — Warp scale */
    --radius-xs: 4px;
    --radius-sm: 6px;
    --radius-md: 8px;
    --radius-lg: 12px;
    --radius-xl: 14px;
    --radius-2xl: 40px;
    --radius-pill: 50px;

    /* Spacing — 8px base, editorial-grade */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 12px;
    --space-4: 16px;
    --space-5: 20px;
    --space-6: 24px;
    --space-8: 32px;
    --space-10: 40px;
    --space-12: 48px;
    --space-16: 64px;
    --space-20: 80px;
    --space-24: 96px;
    --space-32: 128px;

    /* Animation — sharp, no bounce */
    --duration-fast: 150ms;
    --duration-normal: 400ms;
    --duration-slow: 700ms;
    --ease-out: cubic-bezier(0.22, 1, 0.36, 1);
  }
}

/* ============================================
   BASE STYLES
   ============================================ */

@layer base {
  *,
  *::before,
  *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }

  html {
    scroll-behavior: smooth;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
  }

  body {
    font-family: var(--font-matter);
    font-size: 18px;
    line-height: 1.4;
    font-weight: 400;
    background-color: var(--bg);
    color: var(--text);
    min-height: 100vh;
    overflow-x: hidden;
    letter-spacing: -0.01em;
  }

  /* Selection — warm parchment */
  ::selection {
    background-color: rgba(250, 249, 246, 0.15);
    color: var(--text);
  }

  /* Focus — subtle, warm */
  :focus-visible {
    outline: 1px solid var(--border-strong);
    outline-offset: 2px;
  }

  /* Scrollbar — minimal warm dark */
  ::-webkit-scrollbar {
    width: 5px;
    height: 5px;
  }

  ::-webkit-scrollbar-track {
    background: transparent;
  }

  ::-webkit-scrollbar-thumb {
    background: var(--border-strong);
    border-radius: 10px;
  }

  ::-webkit-scrollbar-thumb:hover {
    background: rgba(226, 226, 226, 0.5);
  }

  /* Links — muted, underline on hover */
  a {
    color: inherit;
    text-decoration: none;
  }

  /* Images */
  img {
    max-width: 100%;
    height: auto;
    display: block;
  }

  /* Headings — matter weight */
  h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-matter);
    font-weight: 400;
    letter-spacing: -0.02em;
    line-height: 1.1;
  }
}

/* ============================================
